/*    _   __   ___    _   ____    _    _        _____    ___     _____     | | / /  / _ \  | | |  _ \  | |  | |      |___  |  / _ \   |  ___|     | |/ /  | |_| | | | | |_| | |  \/  |         / /  | |_| |  | |__     |   /   |  _  | | | |  _ /  | |\/| |        / /   |  _  |  |  __|     | |\ \  | | | | | | | | \ \ | |  | |       / /__  | | | |  | |     |_| \_\ |_| |_| |_| |_| |_| |_|  |_|      |_____| |_| |_|  |_|      */#include<bits/stdc++.h> typedef long long ll;using namespace std;#ifndef ONLINE_JUDGE #include "debug.cpp" #else#define kar(...)#endif#define pb push_back#define F first#define S second#define all(x) x.begin(),x.end()#define rall(x) x.rbegin(),x.rend()#define int ll#define endl '\n' const int N = 2e5 + 30, mod = 1e9 + 7, MOD = mod, INF = 1e18 + 10; int freq[20][1 << 17];int dp[1 << 17][20][2]; int work(int mask, int pos, int parity) {    if (pos == 17 && parity) return freq[pos][mask];    if (pos == 17) return 0;    int &ret = dp[mask][pos][parity];    if (ret != -1)return ret;     ret = work(mask, pos + 1, parity); //we left the same actual bit on pos ;     if ((1 << pos) & mask) {        mask ^= (1 << pos);// we flip the current bit        if (parity == 0)ret += freq[pos][mask & ((1 << 1 << pos) - 1)];        ret += work(mask, pos + 1, parity ^ 1);    } else {        mask ^= (1 << pos);// we flip the current bit        ret += freq[pos][mask & ((1 << 1 << pos) - 1)];        ret += work(mask, pos + 1, parity);    }     return ret;} void Solve() {    int n, ans = INF;    cin >> n;     memset(dp, -1, sizeof(dp));    memset(freq, 0, sizeof(freq));     for (int i = 0, x; i < n; i++) {        cin >> x;        for (int j = 0; j < 18; j++)            freq[j][x & ((1 << 1 << j) - 1)]++;    }    for (int i = 0; i < 1 << 17; i++)        ans = min(ans, work(i, 0, 0));     cout << ans << endl;} int32_t main() {#ifndef ONLINE_JUDGE    freopen("input.txt", "r", stdin);    freopen("output.txt", "w", stdout);#endif    ios::sync_with_stdio(0);    cin.tie(0);    int Test_case = 1;    cin >> Test_case;    while (Test_case--) Solve();}